protected void  postTax(boolean _post)
{
    next postTax(_post);
  //  this.postMarkup();
}

protected void  postMarkup()
{
    Markup markup = new Markup(Ledger::accountingCurrency());
    InventTransferLine inventTransferLine;
    InventTransferJourLine inventTransferJourLine;

    InventTransferTotals inventTransferTotals = InventTransferTotals::construct(this.inventTransferJour);

    inventTransferTotals.setUpdateType(InventTransferUpdateType::Shipment);

    inventTransferTotals.calc();

    markup.setTax(inventTransferTotals.tax());

    while select inventTransferLine 
        where inventTransferLine.TransferId == inventTransferTable.TransferId
    {
        InventTable item = InventTable::find(inventTransferLine.ItemId);

        select * from inventTransferJourLine
            where inventTransferJourLine.InventTransId == inventTransferLine.InventTransId &&
                    inventTransferJourLine.TransferId == inventTransferLine.TransferId;

        markup.postInvoice(inventTransferLine.QtyTransfer, inventTransferLine.NetAmount, inventTransferLine, ledgerVoucher, item.DefaultDimension,inventTransferJourLine);
    }
}
